// Base URLs — override with env vars if present
const n8nBase = $vars.N8N_WEBHOOK_BASE_URL  || 'https://launchpad-novaops.app.n8n.cloud/webhook';
const appBase = $vars.GLOBAL_APP_URL_STG    || 'https://stg.nova-ops.space';

const endpoints = [
  // ── Core operator workflows (n8n webhooks) ──────────────────────
  { name: 'AI Operator Main Router',        url: `${n8nBase}/ai-operator-router` },
  { name: 'AI Operator Context Loader',     url: `${n8nBase}/ai-operator-context-loader` },
  { name: 'AI Operator Tool Dispatcher',    url: `${n8nBase}/ai-operator-tool-dispatcher` },
  { name: 'Operator Memory Read',           url: `${n8nBase}/operator-memory-read` },

  // ── Launchpad subagent webhooks (app-side) ───────────────────────
  { name: 'Subagent: Lead Gen',             url: `${appBase}/api/webhooks/tools/lead-gen` },
  { name: 'Subagent: Copywriting',          url: `${appBase}/api/webhooks/tools/copywriting` },
  { name: 'Subagent: Offer Builder',        url: `${appBase}/api/webhooks/tools/offer-building` },
  { name: 'Subagent: Funnel Mapper',        url: `${appBase}/api/webhooks/tools/funnel-mapping` },
  { name: 'Subagent: Content Calendar',     url: `${appBase}/api/webhooks/tools/content-calendar` },
  { name: 'Subagent: Ad Strategy',          url: `${appBase}/api/webhooks/tools/ad-strategy` },
  { name: 'Subagent: Email Sequence',       url: `${appBase}/api/webhooks/tools/email-sequence` },
  { name: 'Subagent: SEO Brief',            url: `${appBase}/api/webhooks/tools/seo-brief` },
  { name: 'Subagent: Competitor Research',  url: `${appBase}/api/webhooks/tools/competitor-research` },
  { name: 'Subagent: Social Planning',      url: `${appBase}/api/webhooks/tools/social-planning` },
  { name: 'Subagent: Sales Script',         url: `${appBase}/api/webhooks/tools/sales-script` },
  { name: 'Subagent: Brand Voice',          url: `${appBase}/api/webhooks/tools/brand-voice` },
  { name: 'Subagent: Analytics',            url: `${appBase}/api/webhooks/tools/analytics` },
  { name: 'Subagent: Automation Builder',   url: `${appBase}/api/webhooks/tools/automation-build` },
  { name: 'Subagent: Client Reporting',     url: `${appBase}/api/webhooks/tools/client-reporting` },
];

// Return one item per endpoint for SplitInBatches
return endpoints.map(e => ({
  json: { _endpoint_name: e.name, _url: e.url }
}));

// Stamp the precise start time immediately before the HTTP ping.
// Must run as close to the HTTP call as possible for accurate timing.
const item = $input.first().json;
return [{ json: Object.assign({}, item, { _start_time: Date.now() }) }];

const response = $input.first().json;
const meta     = $('Code - Set Start Time').first().json;

const endTime        = Date.now();
const responseTimeMs = endTime - (meta._start_time || endTime);

// statusCode = 0 means no HTTP response received (timeout / connection refused)
const statusCode = response.statusCode || 0;

// DOWN if: no response at all, OR wall-clock time hit the 5s ceiling
// Any HTTP status (even 404 / 405) means the server is reachable → UP
const isDown = statusCode === 0 || responseTimeMs >= 5000;

return [{
  json: {
    endpoint_name:    meta._endpoint_name,
    url:              meta._url,
    status:           isDown ? 'down' : 'up',
    status_code:      statusCode,
    response_time_ms: Math.min(responseTimeMs, 5001),
    is_down:          isDown,
    checked_at:       new Date().toISOString()
  }
}];

// SplitInBatches done output delivers ALL processed items accumulated across iterations.
const allResults = $input.all().map(item => item.json);

const failures   = allResults.filter(r => r.is_down);
const upCount    = allResults.length - failures.length;
const checkedAt  = new Date().toISOString();

// ── Slack message ────────────────────────────────────────────────
let slackText;
if (failures.length === 0) {
  slackText = `✅ *Nova OPS Health Check* — All ${allResults.length} endpoints UP (${checkedAt})`;
} else {
  const lines = failures.map(f =>
    `• *${f.endpoint_name}*: HTTP ${f.status_code} · ${f.response_time_ms}ms${
      f.response_time_ms >= 5000 ? ' ⏱ TIMEOUT' : ''}`
  ).join('\n');
  slackText =
    `🔴 *Nova OPS Health Alert — ${failures.length}/${allResults.length} endpoint(s) DOWN*\n\n` +
    lines +
    `\n\n_Checked at: ${checkedAt}_`;
}

// ── Supabase bulk payload ────────────────────────────────────────
const dbRows = allResults.map(r => ({
  endpoint_name:    r.endpoint_name,
  status:           r.status,
  status_code:      r.status_code,
  response_time_ms: r.response_time_ms,
  checked_at:       r.checked_at
}));

return [{
  json: {
    results:     allResults,
    db_rows:     dbRows,
    failures,
    has_failures: failures.length > 0,
    slack_text:   slackText,
    total:        allResults.length,
    up_count:     upCount,
    down_count:   failures.length,
    checked_at:   checkedAt
  }
}];
